import { BullModule } from '@nestjs/bullmq';
import { Module } from '@nestjs/common';
import { ANALYTICS_QUEUE } from '../../common/queues/queue.config';
import { AnalyticsQueueProducer } from '../../infrastructure/messaging/analytics-queue.producer';
import { CatalogModule } from '../catalog/catalog.module';
import { CheckoutService } from './application/services/checkout.service';
import { PointsService } from './application/services/points.service';
import { PointsStrategyResolver } from './application/services/points-strategy-resolver';
import { SessionExpirationService } from './application/services/session-expiration.service';
import { EVENT_PUBLISHER } from './application/interfaces/event-publisher.interface';
import { POINTS_REPOSITORY } from './application/interfaces/points-repository.interface';
import { QR_SIGNER } from './application/interfaces/qr-signer.interface';
import { SESSION_NOTIFIER } from './application/interfaces/session-notifier.interface';
import { SESSION_REPOSITORY } from './application/interfaces/session-repository.interface';
import { UNIT_OF_WORK } from './application/interfaces/unit-of-work.interface';
import { JwtQrSigner } from './infrastructure/crypto/jwt-qr.signer';
import { BullMqEventPublisher } from './infrastructure/events/bullmq-event.publisher';
import { PrismaUnitOfWork } from './infrastructure/persistence/prisma-unit-of-work';
import { PrismaPointsRepository } from './infrastructure/repositories/prisma-points.repository';
import { PrismaSessionRepository } from './infrastructure/repositories/prisma-session.repository';
import { QrController } from './presentation/controllers/qr.controller';
import { SessionController } from './presentation/controllers/session.controller';
import { ValidationController } from './presentation/controllers/validation.controller';
import { SessionGateway } from './presentation/gateways/session.gateway';

/**
 * Checkout module — the single place concrete classes are bound to their ports
 * (README §2.2 Dependency Injection Configuration). Swap an implementation here
 * (e.g. for tests) without touching application code.
 */
@Module({
  imports: [
    CatalogModule, // provides CATALOG_SERVICE
    BullModule.registerQueue({ name: ANALYTICS_QUEUE }),
  ],
  controllers: [SessionController, QrController, ValidationController],
  providers: [
    // Application services
    CheckoutService,
    PointsService,
    PointsStrategyResolver,
    SessionExpirationService,
    // Gateway (also exposed as the notifier port)
    SessionGateway,
    { provide: SESSION_NOTIFIER, useExisting: SessionGateway },
    // Ports → infrastructure (Dependency Inversion)
    AnalyticsQueueProducer,
    { provide: SESSION_REPOSITORY, useClass: PrismaSessionRepository },
    { provide: POINTS_REPOSITORY, useClass: PrismaPointsRepository },
    { provide: QR_SIGNER, useClass: JwtQrSigner },
    { provide: EVENT_PUBLISHER, useClass: BullMqEventPublisher },
    { provide: UNIT_OF_WORK, useClass: PrismaUnitOfWork },
  ],
  exports: [CheckoutService],
})
export class CheckoutModule {}
